import React, { useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Heart, Sparkles, Moon, Sun, Volume2, Zap, Calendar, Star, Smile, Coffee, Music, Flame, Cloud, Umbrella, Camera, Gift, Flower2, Feather, Palette, Rocket, Crown, Diamond, Cherry, Cake, IceCream, Pizza, Apple, Carrot, Cookie } from 'lucide-react';

const availableIcons = {
  Heart, Sparkles, Moon, Sun, Volume2, Zap, Calendar, Star, Smile, Coffee,
  Music, Flame, Cloud, Umbrella, Camera, Gift, Flower2, Feather, Palette,
  Rocket, Crown, Diamond, Cherry, Cake, IceCream, Pizza, Apple, Carrot, Cookie
};

function IconPicker({ paramKey, currentIcon, onSelect, onClose, position }) {
  const pickerRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (pickerRef.current && !pickerRef.current.contains(event.target)) {
        onClose();
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [onClose]);

  return createPortal(
    <div
      ref={pickerRef}
      className="fixed z-[9999] bg-white rounded-2xl shadow-2xl p-4 border-2 border-pink-200 w-72"
      style={{ top: `${position.top}px`, left: `${position.left}px` }}
    >
      <div className="flex items-center justify-between mb-3">
        <span className="text-sm font-bold text-gray-700">选择图标</span>
        <button
          onClick={onClose}
          className="text-gray-400 hover:text-gray-600 text-xl leading-none"
        >
          ×
        </button>
      </div>
      <div className="grid grid-cols-6 gap-2 max-h-64 overflow-y-auto">
        {Object.entries(availableIcons).map(([name, Icon]) => (
          <button
            key={name}
            onClick={() => onSelect(paramKey, name)}
            className={`p-2 rounded-lg transition-all hover:scale-110 ${
              currentIcon === name
                ? 'bg-gradient-to-br from-pink-400 to-purple-400 text-white shadow-lg'
                : 'bg-gray-100 text-gray-600 hover:bg-pink-100'
            }`}
            title={name}
          >
            <Icon size={20} />
          </button>
        ))}
      </div>
    </div>,
    document.body
  );
}

export default IconPicker;
